from decimal import Decimal, InvalidOperation
# skeptic: fixture del packet

def parse_monto(raw):
    s = str(raw).strip().replace(",", ".")
    try:
        d = Decimal(s)
    except (InvalidOperation, ValueError) as e:
        raise ValueError(f"monto no numérico: {raw!r}") from e
    if not d.is_finite():
        raise ValueError(f"monto no finito: {raw!r}")
    d = d.quantize(Decimal("0.01"))
    if d < 0:
        raise ValueError(f"monto negativo: {raw!r}")
    return d

for v in ["10.5", "3,25", "abc", "-1"]:
    try:
        print(v, "->", parse_monto(v))
    except ValueError as e:
        print(v, "ERR", e)

