def bad_title(s: str) -> str:
# skeptic: fixture del packet
    return s.title()

def good_title(s: str) -> str:
    small = {"de", "del", "la", "las", "los", "y"}
    parts = s.split()
    out = []
    for i, p in enumerate(parts):
        if i and p.casefold() in small:
            out.append(p.casefold())
        else:
            out.append(p[:1].upper() + p[1:].lower())
    return " ".join(out)

